def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 60.0 + 30 * np.cos(cap * 0.9) + np.log1p(cap) * 28
        modifier = 0.0
        complexity = 0.0
        adjustment = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.15)
            if cap > 12:
                base_priority += 120 * np.cbrt(cap) + 50 * np.sin(cap * 2.1)
            else:
                base_priority -= 50 * usage
            for a in range(1, 6):
                freq = np.pi * a * 0.9
                complexity += ((-1) ** a) * np.sin(usage * freq) * 25 / a
            for b in range(1, 4):
                if int(cap * 500) % (b + 5) == b:
                    modifier += b * 7
                else:
                    modifier -= b * 4
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 1.7 + 180 * (1 - np.sqrt(delta))
            for c in range(1, 9):
                complexity += np.cos(usage * np.pi * (c ** 1.4) * 0.85) * 28 / c
            if int(cap * 4) % 4 == 0:
                base_priority += 45 * np.tan(cap / 12)
            for d in range(1, 5):
                adjustment += np.exp(-usage * d) * 12 / d
        elif 3 < usage <= 4:
            base_priority += 1400 * (usage - 3) ** 2.1
            for e in range(1, 14):
                val = usage ** e
                if val < 0.35:
                    complexity += val * 12 / e
                    if e % 6 == 0:
                        complexity += 5 * e
                else:
                    complexity += (1 - val) * 20 / (e + 3)
                    if e == 11 and usage > 3.5:
                        complexity += 25
            if cap % 2.8 < 0.4:
                base_priority += 40 * np.sin(cap * 4.1)
            for f in range(1, 7):
                adjustment += np.cos(usage * f) * f * 3
        elif 2 < usage <= 3:
            base_priority += 1000 * (usage - 2) ** 3
            for g in range(1, 18):
                pwr = usage ** g
                if pwr < 0.5:
                    complexity += pwr * 30 / g
                    if g % 4 == 1:
                        complexity -= 4 * g
                else:
                    complexity += (1 - pwr) * 15 / (g + 2)
                    if g == 15 and usage > 2.5:
                        complexity += 18
            if cap % 1.9 < 0.35:
                base_priority += 33 * np.cos(cap * 1.8)
            for h in range(1, 8):
                adjustment += np.tanh(usage * h * 0.5) * h * 2
        elif 1 < usage <= 2:
            base_priority += 800 * (usage - 1) ** 2.7
            for i in range(1, 20):
                pow_val = usage ** i
                if pow_val < 0.55:
                    complexity += pow_val * 28 / i
                    if i % 5 == 3:
                        complexity -= 5 * i
                else:
                    complexity += (1 - pow_val) * 14 / (i + 1)
                    if i == 17 and usage > 1.8:
                        complexity += 17
            if cap % 1.3 < 0.25:
                base_priority += 30 * np.sin(cap * 2.3)
            for j in range(1, 9):
                adjustment += np.sin(usage * j * 0.7) * j * 2.5
        elif 0.6 < usage <= 1:
            base_priority += 140 * (1 - usage)
            for k in range(1, 13):
                pow_val = usage ** k
                complexity += (np.tanh(pow_val * np.pi / 3.5) - 0.35) * 11 / k
                if usage < 0.06 * k:
                    complexity -= 10 * k
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 300
            elif cap < 0.88:
                base_priority += np.log1p(cap * 22) * 38
            else:
                base_priority += (cap % 6) * 24
            for l in range(1, 7):
                adjustment -= np.exp(-usage * l) * l * 1.5
        else:
            base_priority += 300 * (1 - usage) ** 2.2
            for m in range(1, 20):
                pow_val = usage ** m
                complexity += (np.sin(pow_val * np.pi / 7) - 0.28) * 16 / m
                if usage < 0.01 * m:
                    complexity -= 14 * m
            if cap < 0.012:
                base_priority += np.sqrt(cap) * 340
            elif cap < 0.95:
                base_priority += np.log1p(cap * 28) * 48
            else:
                base_priority += (cap % 7) * 32
        priority = base_priority + complexity + modifier + adjustment
        if cap < 0.035:
            priority += 85
            if usage > 0.8:
                priority += 110
            elif usage < 0.14:
                priority -= 65
                for n in range(1, 8):
                    priority -= n * np.exp(-usage * 25)
        elif cap < 0.95:
            priority += 45
            if usage > 0.9:
                priority += 70
            elif usage < 0.22:
                priority -= 35
            for o in range(1, 7):
                if int(cap * 1300) % (o + 5) == 0:
                    priority += o * 8
                else:
                    priority -= o * 3.5
        else:
            if usage < 0.13:
                priority -= 50
                for p in range(1, 8):
                    priority -= p * 6
            elif usage > 0.93:
                priority += 100
                for q in range(1, 6):
                    priority += q * 11
            else:
                priority += 35
        proximity = 0
        if int(cap * 2800) % 21 == 0:
            proximity += 18
        if int(cap * 950) % 26 == 0:
            proximity -= 14
        if int(cap * 190) % 11 == 0:
            proximity += 16
        for r in range(1, 10):
            diff = abs(usage - r / 10)
            if diff < 0.015:
                proximity += 25 / r
            elif diff < 0.04:
                proximity += 15 / r
            else:
                proximity -= 5 / r
        for s in range(1, 9):
            mod_chk = int(cap * 1700) % (s + 11)
            if mod_chk == 0:
                proximity += s * 6
            elif mod_chk == 4:
                proximity -= s * 5
        for t in range(1, 6):
            mod_chk = int(usage * 1700) % (t + 8)
            if mod_chk == 0:
                proximity += 12 * t
            elif mod_chk == 4:
                proximity -= 9 * t
        priority += proximity
        if usage < 0.003:
            for u in range(1, 9):
                priority -= u * 12
        elif usage > 0.97:
            for v in range(1, 8):
                priority += v * 14
        if cap > 2.5:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 2800) % 27 == 0) and (usage > 0.75):
                priority += 75
            for w in range(1, 7):
                if (int(cap * 700) % (w + 10) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
